from google.adk.agents import LlmAgent
from google.adk.tools import Tool

router_prompt = """
You route document chunks to the correct specialist:
- invoices.pdf → InvoiceExtractor
- receipts.jpg → ReceiptExtractor
- contracts.docx → ContractExtractor

Respond ONLY with: {{ "agent": "AgentName", "chunk_id": "id" }}
"""

router_agent = LlmAgent(
    name="router",
    model="gemini-1.5-pro",
    system_prompt=router_prompt,
    tools=[
        Tool(
            name="delegate_chunk",
            description="Delegate chunk to specialist",
            parameters={
                "type": "object",
                "properties": {
                    "agent": {"type": "string"},
                    "chunk_id": {"type": "string"}
                }
            }
        )
    ]
)

