from google.adk import AgentWorkflow
from vex.guards import Guard

@vex.guard(extraction_suite)
def before_agent_callback(agent_name: str, input_data: dict, session_state: dict) -> bool:
    """Vex verification before each agent execution"""

    # Verify input contains document text
    if 'text' not in input_data:
        vex.log_error(f"{agent_name}: Missing document text")
        return False

    # Schema compliance for tool parameters
    if 'tool_calls' in input_data:
        for tool_call in input_data['tool_calls']:
            if not extraction_guard.validate(tool_call.get('args', {})):
                vex.log_error(f"{agent_name}: Schema violation in {tool_call['name']}")
                return False

    # Session state consistency
    if 'extraction_progress' in session_state:
        if not isinstance(session_state['extraction_progress'], list):
            vex.log_error(f"{agent_name}: Corrupted session state")
            return False

    return True

# Apply to ADK workflow
workflow = AgentWorkflow(agents=[router_agent, invoice_extractor, validator_agent])
workflow.add_callback('before_agent', before_agent_callback)

from typing import Dict, Any

@vex.guard(extraction_suite)
def after_agent_callback(agent_name: str, output: Dict[str, Any], session_state: Dict) -> str:
    """Post-agent verification with auto-recovery"""

    # Parse and validate structured output
    try:
        result = ExtractionResult.parse_obj(output.get('content', {}))

        # Completeness check
        missing = []
        for invoice in result.invoices:
            if not invoice.line_items:
                missing.append(f"Invoice {invoice.invoice_number}: no line items")

        if missing and result.confidence < 0.8:
            # Trigger retry with Router Agent
            vex.trigger_recovery(
                agent_name="router_agent",
                input_data={"retry_chunk": output.get('chunk_id'), "issues": missing}
            )
            return "retry"

    except Exception as e:
        vex.log_error(f"{agent_name}: {str(e)}")
        return "failed"

    # Success: update session state
    session_state.setdefault('extraction_progress', []).append({
        'agent': agent_name,
        'chunk_id': output.get('chunk_id'),
        'confidence': result.confidence
    })

    return "success"

workflow.add_callback('after_agent', after_agent_callback)
